+/// Fold (X != -1) & ((X + 1) u<= Y) --> X u< Y
+/// This is valid because:
+/// - If X = -1 (all ones), then (X != -1) is false, so the result is false.
+///   Also, X u< Y is false when X is the maximum value.
+/// - If X != -1, then (X + 1) doesn't wrap, and (X + 1) u<= Y is equivalent to X u< Y.
+static Value *foldICmpNeAllOnesAndICmpUleAddOne(ICmpInst *NeICmp, ICmpInst *UleICmp,
+                                                InstCombiner::BuilderTy &Builder) {
+  // Check if NeICmp is (X != -1)
+  ICmpInst::Predicate NePred = NeICmp->getPredicate();
+  if (NePred != ICmpInst::ICMP_NE)
