+  ICmpInst::Predicate UlePred = UleICmp->getPredicate();
+  if (UlePred != ICmpInst::ICMP_ULE)
+    return nullptr;
+  
+  Value *UleOp0 = UleICmp->getOperand(0);
+  Value *UleOp1 = UleICmp->getOperand(1);
+  
