+  Value *AddX, *AddC;
+  const APInt *AddConst;
+  if (!match(UleOp0, m_Add(m_Value(AddX), m_APInt(AddConst))))
+    return nullptr;
+  
+  // Check if AddX is the same as NeOp0 (the X in X != -1)
+  if (AddX != NeOp0)
+    return nullptr;
+  
+  // Check if the constant is 1
+  if (!AddConst->isOne())
+    return nullptr;
+  
+  // Pattern matched: (X != -1) & ((X + 1) u<= Y) --> X u< Y
